mapper.select:
SELECT ID AS userId, NAME AS name, AVATAR AS avatar, POINT AS point FROM mt_user WHERE POINT > 0 AND STATUS = 'A' AND IS_STAFF = 'N'
AND MERCHANT_ID = #{merchantId}
ORDER BY POINT DESC LIMIT 200

SELECT u.ID AS userId, u.NAME AS name, u.AVATAR AS avatar, SUM(p.AMOUNT) AS point FROM mt_point p INNER JOIN mt_user u ON p.USER_ID = u.ID WHERE p.AMOUNT > 0 AND p.STATUS = 'A' AND u.STATUS = 'A' AND u.IS_STAFF = 'N'
AND u.MERCHANT_ID = #{merchantId}
AND p.CREATE_TIME >= #{startTime}
AND p.CREATE_TIME < #{endTime}
GROUP BY u.ID, u.NAME, u.AVATAR HAVING SUM(p.AMOUNT) > 0 ORDER BY SUM(p.AMOUNT) DESC LIMIT 200
